/* eslint-disable @next/next/no-img-element */
"use client";

import { ShoppingCart } from "lucide-react";
import Link from "next/link";

import { useStorefront } from "@/components/providers/StorefrontProvider";
import { formatIQD, getProductName } from "@/lib/storefront";
import type { Product } from "@/lib/types";
import { useCartStore } from "@/store/cart";

type ProductCardProps = {
  product: Product;
};

export function ProductCard({ product }: ProductCardProps) {
  const addItem = useCartStore((state) => state.addItem);
  const { language, isRTL, t } = useStorefront();
  const hasDiscount =
    typeof product.original_price === "number" &&
    product.original_price > product.price_iqd;

  return (
    <article className="group overflow-hidden rounded-[2rem] border border-emerald-100 bg-white shadow-soft transition hover:-translate-y-1 hover:border-primary/30">
      <Link href={`/product/${product.id}`} className="block">
        <div className="relative aspect-square overflow-hidden bg-[linear-gradient(135deg,#f9fff9,#eef8f0)]">
          <img
            src={product.image_url}
            alt={getProductName(product, language)}
            className="h-full w-full object-contain p-6 transition duration-500 group-hover:scale-105"
            loading="lazy"
          />
          {hasDiscount ? (
            <span
              className={`absolute top-4 rounded-full bg-secondary px-3 py-1 text-xs font-bold text-slate-900 ${
                isRTL ? "right-4" : "left-4"
              }`}
            >
              {t("home.offers")}
            </span>
          ) : null}
        </div>
      </Link>

      <div className="space-y-4 p-5">
        <div className={isRTL ? "text-right" : "text-left"}>
          <Link
            href={`/product/${product.id}`}
            className="line-clamp-2 text-base font-semibold text-slate-900 transition group-hover:text-primary"
          >
            {getProductName(product, language)}
          </Link>
          <div className="mt-3 flex items-end gap-3">
            <span className="text-lg font-bold text-primary">
              {formatIQD(product.price_iqd, language)}
            </span>
            {hasDiscount ? (
              <span className="text-sm text-slate-400 line-through">
                {formatIQD(product.original_price ?? product.price_iqd, language)}
              </span>
            ) : null}
          </div>
        </div>

        <button
          type="button"
          onClick={() => addItem(product)}
          disabled={product.stock_quantity <= 0}
          className={`inline-flex w-full items-center justify-center gap-2 rounded-2xl px-4 py-3 text-sm font-semibold transition ${
            product.stock_quantity > 0
              ? "bg-primary text-white hover:bg-[#256a2a]"
              : "cursor-not-allowed bg-slate-200 text-slate-500"
          }`}
        >
          <ShoppingCart size={16} />
          <span>
            {product.stock_quantity > 0
              ? t("product.addToCart")
              : t("product.outOfStock")}
          </span>
        </button>
      </div>
    </article>
  );
}
